def has_close_elements(numbers, threshold):
    if not numbers or len(numbers) == 1 or threshold < 0:
        return False

    numbers.sort()
    for i in range(len(numbers) - 1):
        if numbers[i + 1] - numbers[i] < threshold:
            return True

    return False
